package pages;

import base.BasePage;
import org.openqa.selenium.WebDriver;
import static org.assertj.core.api.Assertions.*;
import static pageObjects.AccountActivityPage.*;

/**
 * AccountActivityPage.java
 * Page actions and assertions for Account Activity feature
 * Generated by: ScriptGenerationAgent | Framework: selenium-java-hybrid
 */
public class AccountActivityPage extends BasePage {

    public AccountActivityPage(WebDriver driver) {
        super(driver);
    }

    // ── Navigation ────────────────────────────────────────────────────────────

    public void navigate() {
        String url = getConfigProperty("BASE_URL", "http://localhost:3000");
        driver.get(url + "/account-activity");
        waitForPageLoad();
    }

    // ── Actions ───────────────────────────────────────────────────────────────

    // Reserved for future filters/interactions

    // ── Assertions ────────────────────────────────────────────────────────────

    public void verifyActivityPageLoaded() {
        wait(2);
        assertThat(isElementVisible(PAGE_HEADING))
            .as("Account activity page heading should be visible")
            .isTrue();
        assertThat(driver.getCurrentUrl())
            .as("URL should contain /account-activity or /activity")
            .containsAnyOf("/account-activity", "/activity");
    }

    public void verifyLoginHistoryDisplayed() {
        wait(2);
        assertThat(isElementVisible(LOGIN_HISTORY))
            .as("Login history should be visible")
            .isTrue();
    }

    public void verifyActivityTimestampsPresent() {
        wait(2);
        assertThat(getElementCount(ACTIVITY_TIMESTAMP))
            .as("Activity timestamps should be present")
            .isGreaterThan(0);
    }

    public void verifyActivityDetailsComplete() {
        wait(2);
        assertThat(getElementCount(ACTIVITY_DETAILS))
            .as("Activity details should be complete")
            .isGreaterThan(0);
    }
}
